export interface ConsulOptions {
    /**
     * Consul Agent Host
     */
    host?: string;
    /**
     * Consul Agent Port
     */
    port?: string | number;
    /**
     * Consul Agent UDS
     */
    socketPath?: string;
    /**
     * Logger 实例
     */
    logger?: ILogger;
    /**
     * 是否输出 warning，本地默认 false
     */
    enableWarning?: boolean;
    /**
     * 缓存时间，单位 ms，默认 15s
     */
    cacheTime?: number;
    /**
     * 是否开启 debug ( 调试用 )，默认 false
     */
    debug?: boolean;
}
export interface LookupOptions {
    /**
     * 服务 Cluster
     */
    cluster?: string;
    /**
     * 服务 IDC
     */
    idc?: string;
    /**
     * 服务 address family 过滤条件
     * - dual-stack: 返回 IPv4 + IPv6 地址
     * - v4: 返回 IPv4 地址
     * - v6: 返回 IPv6 地址
     */
    addrfam?: string;
    /**
     * 服务地址合并条件，只有当 options.addrfam 是 dual-stack 时，才会生效
     * - v4: 以 IPv4 为主
     * - v6: 以 IPv6 为主
     */
    unique?: string;
    /**
     * 返回条数
     */
    limit?: number;
    /**
     * 是否不使用缓存
     */
    nocache?: boolean;
    /**
     * 请求 Consul Agent 时使用的 x-consul-result-hash 值
     */
    consulHash?: string;
    /**
     * 超时时间，单位 ms，默认 3s
     */
    timeout?: number;
    /** @deprecated */
    env?: string;
    /** @deprecated */
    enableTrafficScheduling?: boolean;
    /** @deprecated */
    withAddrFamily?: string;
}
export interface Endpoint {
    host: string;
    port: number;
    /** @deprecated use addr instead */
    uri: string;
    addr: string;
    cluster: string;
    env: string;
    weight: number;
    tags: {
        [key: string]: string;
    };
}
export interface ILogger {
    fatal(message: string, ...splat: any[]): any;
    error(message: string, ...splat: any[]): any;
    warn(message: string, ...splat: any[]): any;
    info(message: string, ...splat: any[]): any;
    debug(message: string, ...splat: any[]): any;
    trace(message: string, ...splat: any[]): any;
}
